mapper.select:
select g.out_put_id as outPutId, g.pollutant_code as pollutantCode, g.rtd_unit as rtdUnit, g.cou_unit as couUnit, g.decimal_places as decimalPlaces, g.mon_factor as monFactor, g.pollutant_sort as pollutantSort, p.pollutant_name_cn as pollutantNameCn, p.pollutant_unit_en as pollutantUnitEn, p.unit_pf_en as unitPfEn from t_ent_output_pollutant g left join t_bas_pollutant_code p on p.pollutant_code = g.pollutant_code where g.out_put_id in
#{outPutId}
order by g.pollutant_sort desc

mapper.update:
update t_ent_output_pollutant
set pollutant_sort = #{pollutantSort}, is_zero_alarm = #{isZeroAlarm}, is_continuity_alarm = #{isContinuityAlarm},
    is_negative_alarm = #{isNegativeAlarm}, monthly_limit_value = #{monthlyLimitValue}, over_maxValue = #{overMaxvalue},
    over_minValue = #{overMinvalue}, rtd_unit = #{rtdUnit}, cou_unit = #{couUnit}, decimal_places = #{decimalPlaces},
    update_time = #{updateTime}, mon_factor = #{monFactor}
where out_put_poll_id = #{outPutPollId}

update t_ent_out_put_info
set pollutant_code = (
    select GROUP_CONCAT(pollutant_code ORDER BY pollutant_sort DESC SEPARATOR ',')
    from t_ent_output_pollutant
    where out_put_id = #{outPutId}
)
where out_put_id = #{outPutId}

mapper.select:
select monthly_limit_value
from t_ent_output_pollutant
where out_put_id = #{outPutId} and pollutant_code = #{pollCode}
